import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { EventItem, RsvpStatus } from '../../core/models';

/**
 * GatherUp public event detail. Shows capacity / confirmed / waitlist counts and
 * a login-gated RSVP / Cancel CTA. Anonymous users are sent to /login.
 * Mock data is a signal<EventItem[]>; service_agent wires ApiService.getEvent(id)
 * and rsvp()/cancelRsvp().
 */
@Component({
  selector: 'app-event-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './event-detail.component.html',
  styleUrl: './event-detail.component.css',
})
export class EventDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly acting = signal(false);

  // Held as a list so mockup_cleaner clears it and service_agent can wire the API.
  readonly events = signal<EventItem[]>([
    {
      id: 'e1', venueId: 'v1', title: 'Indie Synth Night',
      description:
        'A cozy evening of live synth-pop from three local acts. Doors at 8pm, ' +
        'first set at 8:30. Full bar on site, all ages until 10pm.',
      category: 'Music', startsAt: '2026-07-18T20:00:00.000Z', endsAt: '2026-07-18T23:00:00.000Z',
      capacity: 120, confirmedCount: 87, waitlistCount: 0, myRsvpStatus: null,
      venue: { id: 'v1', name: 'The Warehouse', address: '12 Dock Road', defaultCapacity: 150 },
    },
    {
      id: 'e3', venueId: 'v1', title: 'Intro to Watercolor',
      description: 'Hands-on beginner workshop — materials provided. This session is full; ' +
        'RSVP to join the waitlist and we\'ll auto-promote you if a spot opens.',
      category: 'Workshop', startsAt: '2026-07-22T18:30:00.000Z', endsAt: '2026-07-22T20:30:00.000Z',
      capacity: 1, confirmedCount: 1, waitlistCount: 2, myRsvpStatus: null,
      venue: { id: 'v1', name: 'The Warehouse', address: '12 Dock Road', defaultCapacity: 150 },
    },
  ]);

  readonly eventId = signal<string>('');
  readonly event = computed<EventItem | undefined>(() =>
    this.events().find((e) => e.id === this.eventId()) ?? this.events()[0],
  );

  readonly spotsLeft = computed(() => {
    const e = this.event();
    return e ? Math.max(0, e.capacity - (e.confirmedCount ?? 0)) : 0;
  });
  readonly isFull = computed(() => this.spotsLeft() === 0);

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.eventId.set(this.route.snapshot.paramMap.get('id') ?? '');
    // service_agent: this.api.getEvent(this.eventId()).subscribe(e => this.events.set([e]));
  }

  /** RSVP CTA. Anonymous users are redirected to login (login-gated). */
  onRsvp(): void {
    if (!this.auth.isLoggedIn()) {
      this.router.navigate(['/login']);
      return;
    }
    this.acting.set(true);
    // Optimistic mock: fill a spot (or waitlist if full).
    this.mutate((e) => {
      if (this.isFull()) {
        return { ...e, myRsvpStatus: 'waitlist' as RsvpStatus, waitlistCount: (e.waitlistCount ?? 0) + 1 };
      }
      return { ...e, myRsvpStatus: 'confirmed' as RsvpStatus, confirmedCount: (e.confirmedCount ?? 0) + 1 };
    });
    this.acting.set(false);
    // service_agent: this.api.rsvp(this.eventId()).subscribe(...)
  }

  onCancel(): void {
    this.acting.set(true);
    this.mutate((e) => {
      const wasConfirmed = e.myRsvpStatus === 'confirmed' || e.myRsvpStatus === 'checkedIn';
      return {
        ...e,
        myRsvpStatus: 'cancelled' as RsvpStatus,
        confirmedCount: wasConfirmed ? Math.max(0, (e.confirmedCount ?? 0) - 1) : e.confirmedCount,
      };
    });
    this.acting.set(false);
    // service_agent: this.api.cancelRsvp(this.eventId()).subscribe(...)
  }

  private mutate(fn: (e: EventItem) => EventItem): void {
    const id = this.event()?.id;
    this.events.update((list) => list.map((e) => (e.id === id ? fn(e) : e)));
  }

  statusBadge(status?: RsvpStatus | null): { cls: string; label: string } | null {
    switch (status) {
      case 'confirmed': return { cls: 'badge-ok', label: 'You\'re going' };
      case 'checkedIn': return { cls: 'badge-info', label: 'Checked in' };
      case 'waitlist': return { cls: 'badge-warn', label: 'On the waitlist' };
      default: return null;
    }
  }

  when(iso: string): string {
    return new Date(iso).toLocaleString(undefined, {
      weekday: 'long', month: 'long', day: 'numeric', hour: 'numeric', minute: '2-digit',
    });
  }
}
